{"purpose":"S11 planning validation activity lookup","runtime":"bash","script":"python3 - <<'PY'
from pathlib import Path
for base in ['.gsd/activity','.gsd/journal']:
    p=Path(base)
    if not p.exists():
        print(f'{base}: missing')
        continue
    matches=[str(x) for x in p.rglob('*') if x.is_file() and ('validate' in x.name.lower() or 'M001' in x.name)]
    print(f'{base}: {len(matches)} validate/M001 files')
    for m in matches[:20]:
        print('  '+m)
PY","timeout_ms":120000}

